external_knowledge:
- 'In Committee' means the bill is currently being reviewed and discussed by a committee; 
- 'Democrat' refers to the political party affiliation of the sponsor; 
- 'more than two actions on average' implies bills with multiple actions, which could be indicative of controversy or complexity.

sql:
SELECT SUM(total_votes) AS total_votes
FROM voting_records
WHERE bill_id = 1;

SELECT name, affiliation
FROM witnesses
WHERE affiliation = 'Teachers Union';

SELECT sponsor_id
FROM committee_members
WHERE committee_id = 0;

SELECT title
FROM bills
ORDER BY last_updated DESC;

SELECT bill_id, SUM(total_votes) AS total_votes_cast
FROM voting_records
GROUP BY bill_id;
